// AUTO-GENERATED by @aquila/stories compiler. Do not edit by hand.

import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十二點半。雨沒有停，只是換了一種節奏——從早晨那種密集的、針一樣的直刺，變成了一種更慢、更沉的、帶著重量的壓迫。雲層壓得很低，低到從禮堂後台的氣窗望出去，幾乎能看見雲底的紋路，像一塊被擰了無數次也擰不乾的灰色抹布。", background: Background.Chapter_2_Ch2_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在禮堂後台通往裝卸區的走廊裡。這條走廊比校史館的準備區更寬，兩側堆滿了各種設備箱——黑色的、灰色的、銀色的，有些貼著膠帶標籤，有些什麼都沒有，只是沉默地靠在牆邊，像一排等待被裝進棺材的行李。", background: Background.Chapter_2_Ch2_Act7_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)車輛進出表。", background: Background.Chapter_2_Ch2_Act7_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)早上在保全室桌上瞥到的那行字——「17:40，校務廂型車，側門出發。封路前最後一班登記工作車。」", background: Background.Chapter_2_Ch2_Act7_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我記住了。三個小時前它只是一行字。現在我需要知道它是什麼。", background: Background.Chapter_2_Ch2_Act7_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從早上開始就在數。數所有可能離開校園的車。", background: Background.Chapter_2_Ch2_Act7_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)媒體車。早上九點之後就沒再動過，記者都進了禮堂，車停在訪客區，輪胎上積了水。", background: Background.Chapter_2_Ch2_Act7_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)餐飲補給車。卸完最後一批食材就熄火了，司機在餐廳吃飯，駕駛座的車門沒關，但沒有人上去。", background: Background.Chapter_2_Ch2_Act7_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)校務廂型車。車牌我記下了。早上停在裝卸區靠裡的位置，後門開著，裡面是空的。", background: Background.Chapter_2_Ch2_Act7_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)它今天會走。", background: Background.Chapter_2_Ch2_Act7_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊盡頭是裝卸區——一個半敞開的水泥平台，頂部有鐵皮雨棚，雨棚的邊緣掛著一排不斷滴水的塑料布。平台外面就是側門通道，通道連接著校園外圍的道路，道路盡頭是那扇平時很少打開的側門鐵柵欄。", background: Background.Chapter_2_Ch2_Act7_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "平台上有動靜。幾個穿著反光背心的工作人員正在搬運器材箱，動作比平時急，腳步踩在濕滑的水泥地上，鞋底發出吱嘎的摩擦聲。一個中年男人站在平台邊緣，手裡拿著一張夾在寫字板上的紙，不時低頭看一眼，又抬頭指揮。", background: Background.Chapter_2_Ch2_Act7_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)那輛車。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校務廂型車停在平台外側。深藍色的車身，車身上印著褪色的校徽和「鳴海高中校務車」幾個字。後門大開著，裡面已經放了一些東西——幾個黑色的硬殼箱，用彈力繩固定在車廂壁上，還有一疊藍色的塑膠籃，裡面裝著纏成圈的電纜。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)它真的要下山。早上那行字是真的。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "攝影組備份箱先上，硬碟箱最後裝，怕震。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "那邊那幾個黑色的——對，貼標籤的那幾個——全部裝到右邊靠裡。繩子拉緊點，山路彎多。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)攝影組備份箱。硬碟。直播器材。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這車裝的是直播備份設備。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他退回走廊陰影裡，背靠著牆壁，裝作在整理志工背心的樣子。他的眼睛沒有離開過裝卸區。工作人員搬著一個又一個箱子經過他面前——藍色的塑膠工具箱、灰色的折疊腳架袋、黑色的硬殼箱。箱子上有標籤，有些是列印的，有些是手寫的。「燈光組」「音控」「舞台布景」「攝影組備份」。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)攝影組備份。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是「攝影器材」。是「備份」。備份的意思是——原本的東西在別的地方，這些是複製品，或者存檔。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊息裡說的是「相機」。不是攝影組。不是備份。是相機。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不一樣的東西。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他讓自己呼吸放慢。心律偏快，但還在可控範圍內。他把注意力從「相機」這個詞上拉回來，重新放在更重要的事情上。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)時間表。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)17:20裝車。17:40從側門出發。17:55之前應該通過主山路管制點。18:00之後只准已登記的工作車、救援車和警務車通行。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)它是封路前最後一班登記工作車。它有合法的離校理由。它有登記。它有任務。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)它是這座學校裡唯一能在今天合法離開的東西。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是我選它。是沒有別的東西可選。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "平台邊緣那個拿寫字板的中年男人開始打電話。他的聲音不大，但裝卸區的回音把每個字都送進了走廊裡。顧言聽見了——不是因為他想偷聽，是因為那個聲音正在往他耳朵裡灌。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "是林主任。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "對，側門那邊準備好了。裝車大概五點二十開始，四十分出發。嗯——對，就是那輛校務車。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任的聲音聽起來比早上更緊。不是那種面對學生時的官僚式防禦，而是另一種——更私密的、更接近真實的焦躁。他的手指在寫字板邊緣快速敲了三下，像在倒數什麼。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "正門那邊堵住了，訪客車還有媒體車停了一排，出去也繞不開。我已經跟他們說了——", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他頓了一下。餘光掃了一圈平台，確認沒有不該在場的人。顧言往牆壁的陰影裡又縮了半步。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "這車別走正門，正門堵住了。看天候，必要時走後山維修路。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)後山維修路。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "五個字。林主任說這五個字的時候，語氣和說「正門堵住了」一樣隨意，像在討論一條普通的繞行路線。但顧言注意到了一個細節——", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他說「必要時」。不是「可能」，不是「天氣不好的話」。是「必要時」。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「必要時」是一個條件。條件的背後有一個判斷者。誰來判斷什麼時候是「必要」？", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這不是天氣調度。天氣調度不會用「必要時」這個詞。天氣調度會說「看雨勢」「看路況」。他說的是「必要時」。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)——他在等一個指令。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任掛了電話。他把寫字板夾在腋下，雙手插進西裝褲口袋裡，在平台上來回走了幾步。皮鞋踩在積水的水泥地上，步頻比正常快了半拍。他推了推眼鏡。又推了一次。第三次推眼鏡的時候，他的手停在鏡框上多停留了一秒，像是在借助那個動作掩飾什麼。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在緊張。和早上在校史館一樣，他在害怕。但他怕的不是同一件事。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)早上他怕的是照片。現在他怕的是這輛車。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個工作人員從車廂裡跳出來，走到林主任面前。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "主任，攝影組那邊說備份硬碟還在拷，可能要晚十分鐘。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "晚十分鐘？不行。十七點四十必須走。再晚就趕不上管制點了。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.LinZhuren_Panicked },
    { characterId: CharacterId.Staff, character: "工作人員", dialogue: "他們說訊號不穩，拷貝速度慢——", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.LinZhuren, character: "林主任", dialogue: "那就催。直播訊號不穩才需要把備份送下山，這是唯一的理由。備份沒跟上，這趟車就沒有意義。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.LinZhuren_Stern },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「直播訊號不穩才需要把備份送下山。」", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這個理由很合理。百年校慶直播，颱風天網路不穩，把備份硬碟送到山下合作媒體站點做雙保險。任何一個聽到這句話的人都會覺得正常。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但林主任說「備份沒跟上，這趟車就沒有意義」的時候，他的手在抖。和早上拿照片的時候一樣。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)一個正常的校務調度，不會讓行政主任這麼怕。", background: Background.Chapter_2_Ch2_Act7_S1, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言把這些細節一個一個收進腦子裡，像往口袋裡塞石頭。每一個都沉，每一個都硌手，但他需要它們——需要重量，需要粗糙的觸感，需要能踩在上面的東西。", background: Background.Chapter_2_Ch2_Act7_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他離開走廊，走進裝卸區旁邊的器材暫存室。這裡比走廊更暗，只有頭頂一盞日光燈管在嗡嗡作響，光線被堆到天花板附近的設備箱切割成零碎的塊面。空氣裡有塑膠和金屬的味道，混著從門縫裡滲進來的潮氣。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)攝影組備份箱。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看到了。右邊靠牆的架子上，有三個黑色的硬殼箱並排放著，箱面上貼著標籤——「攝影組備份」「攝影組備份」「直播訊號備份」。箱子的規格一樣，大約六十公分長，帶密碼鎖扣，表面有磨損痕跡，但鎖扣是完好的。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)備份箱。硬碟。直播設備。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)沒有相機。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這裡只有備份箱和硬碟箱。沒有任何東西標著「相機」。沒有任何東西的形狀像一個相機包。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)訊息裡說的是「相機」。這裡沒有相機。這輛車裝的是直播備份設備，不是相機。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)它和訊息沒有關係。它只是恰好在封路前要下山的一輛校務車。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)——恰好在封路前。恰好在十八點之前。恰好是唯一能合法離開的東西。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)世界上沒有這麼多「恰好」。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但我沒有選擇。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的手指在最近的硬殼箱上停了一下。箱面是涼的，帶著輕微的震動——不知道是隔壁裝卸區的搬運震動傳過來的，還是這棟老樓的水管在響。他縮回手，往門口退了一步。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他聽見了聲音。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是從裝卸區傳來的。是從暫存室更裡面、更暗的地方傳來的。一聲很輕的「咔」——硬塑膠卡扣被撥開的聲音。然後是一聲更輕的「嗒」——箱子蓋被掀開又迅速合上的聲音。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)有人在裡面。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他屏住呼吸，側身靠向架子邊緣，透過設備箱之間的縫隙往裡看。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "暫存室最深處，靠著後牆的位置，有一個人影。那人背對著他，正蹲在一排設備箱前面。他的手剛剛合上一個箱蓋，動作很快，快到像是在確認什麼而不是取東西——開、看、合，三個動作一氣呵成，像一套練習過很多次的流程。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯韓越。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "路燈——不，是頭頂日光燈管透過設備箱縫隙漏下來的碎光——照到了那人脖子上的藍底白字吊牌。「舞台組」三個字在昏暗裡反了一下光。他的右手擺動幅度比左手小，手背上有幾道暗紅色的細痂。不會認錯。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在開箱子。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他剛才打開了一個箱子，看了裡面的東西，然後合上了。動作很快，像是在確認什麼有沒有在裡面。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在找東西。或者在放東西。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)——他在偷相機？", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越站起來，用手背推了一下箱子，讓它回到架子上原來的位置。他轉過身，朝門口走。走了兩步，突然停住了。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越的頭偏了一個角度。他在看暫存室入口的方向——顧言的方向。燈光從他背後打過來，把他的臉切成了明暗兩半。他的眉頭擠在一起，嘴唇壓成一條線，整個人像一台突然收到錯誤信號的機器，停擺了半秒。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他看到我了。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不——不確定。這裡很暗。我在架子的陰影裡。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)但他知道有人在。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩秒。韓越站在原地，目光釘在暫存室入口的黑暗裡。然後他的嘴角動了一下——不是笑，是某種很難解讀的微表情，像在壓下一個判斷。他收回視線，轉身大步走出了暫存室。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他沒有過來。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他看到了有人，但他沒有過來確認。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果他在偷東西，他應該怕被人看到。他應該過來確認我是誰，或者直接跑。他兩個都沒做。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)如果他在設陷阱，他應該假裝沒看到，然後在暗處等我。他沒有。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他只是看了我一眼，然後走了。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)像是——確認完了。確認什麼？", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他靠在架子上，後背抵著冰涼的金屬邊緣，心跳在耳膜裡一下一下地撞。他等了三十秒。暫存室裡恢復了安靜，只有頭頂燈管的嗡嗡聲和遠處裝卸區的搬運動靜。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)韓越在裝卸區。韓越在碰器材箱。韓越和許星棠有關係。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)昨天——上一輪——他對我說「你離她遠一點」。他看起來像在威脅我。但也許——", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不。不要想太多。不要被干擾。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我現在需要的事只有一件：在十七點四十分之前，坐上那輛車。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)韓越在做什麼、林主任在怕什麼、許星棠知道什麼——這些都不是我現在能解決的問題。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我只有一件事能做。離開。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從暫存室走出來。走廊裡的日光燈把他的影子拉得很長，投在對面的設備箱上，像一個被壓扁的人形。裝卸區的搬運還在繼續，工作人員的喊聲和箱子碰撞的聲音混在一起，形成一種持續的低頻噪音，蓋住了他離開的腳步聲。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任已經不在平台上了。他走之前留下了一張紙，用寫字板壓在平台邊緣的水泥欄杆上。顧言經過的時候，餘光掃到了紙面上的字。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)調度單。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)校務廂型車。任務：直播備份器材運送。出發：17:40，側門。路線：主山路→管制點。備註：視天候調整。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)路線欄旁邊有一行用鉛筆寫的字，筆跡比列印的字體潦草得多——「後山維修路待命」。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)待命。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)誰的命令？", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有停步。他繼續走，走過裝卸區，走過走廊，走回禮堂的主通道。他的步伐平穩，速度正常，和任何一個在校慶當天穿著志工背心走來走去的學生沒有區別。", background: Background.Chapter_2_Ch2_Act7_S2 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)十七點二十裝車。十七點四十出發。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)我還有四個多小時。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)夠了。", background: Background.Chapter_2_Ch2_Act7_S2, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身後，裝卸區的雨棚邊緣，雨水匯成一條不斷的水簾，落在水泥地上，濺起細密的水霧。那輛深藍色的校務廂型車安靜地停在平台外側，後門敞開著，像一張等待被填滿的嘴。", background: Background.Chapter_2_Ch2_Act7_S2 },
];
